/**
 * Notification module - sends alerts via email, SMS, and push.
 * Note: the validation and formatting logic is duplicated across all three functions.
 */

export function sendEmail(recipient, subject, body) {
  if (!recipient || typeof recipient !== 'string') {
    throw new Error('Invalid recipient');
  }
  if (!subject || typeof subject !== 'string') {
    throw new Error('Invalid subject');
  }
  const cleanRecipient = recipient.trim().toLowerCase();
  const timestamp = new Date().toISOString();
  const formatted = `[${timestamp}] To: ${cleanRecipient} | ${subject}: ${body}`;
  return { type: 'email', message: formatted, recipient: cleanRecipient };
}

export function sendSms(recipient, subject, body) {
  if (!recipient || typeof recipient !== 'string') {
    throw new Error('Invalid recipient');
  }
  if (!subject || typeof subject !== 'string') {
    throw new Error('Invalid subject');
  }
  const cleanRecipient = recipient.trim().toLowerCase();
  const timestamp = new Date().toISOString();
  const formatted = `[${timestamp}] To: ${cleanRecipient} | ${subject}: ${body}`;
  return { type: 'sms', message: formatted, recipient: cleanRecipient };
}

export function sendPush(recipient, subject, body) {
  if (!recipient || typeof recipient !== 'string') {
    throw new Error('Invalid recipient');
  }
  if (!subject || typeof subject !== 'string') {
    throw new Error('Invalid subject');
  }
  const cleanRecipient = recipient.trim().toLowerCase();
  const timestamp = new Date().toISOString();
  const formatted = `[${timestamp}] To: ${cleanRecipient} | ${subject}: ${body}`;
  return { type: 'push', message: formatted, recipient: cleanRecipient };
}

import { sendEmail, sendSms, sendPush } from '../src/notifications.js';

describe('notifications', () => {
  it('sendEmail returns correct type and formatted message', () => {
    const result = sendEmail('Alice@Test.com', 'Hello', 'World');
    expect(result.type).toBe('email');
    expect(result.recipient).toBe('alice@test.com');
    expect(result.message).toContain('Hello: World');
  });

  it('sendSms returns correct type', () => {
    const result = sendSms('Bob@Test.com', 'Alert', 'Fire');
    expect(result.type).toBe('sms');
    expect(result.recipient).toBe('bob@test.com');
  });

  it('sendPush returns correct type', () => {
    const result = sendPush('Carol@Test.com', 'Update', 'New version');
    expect(result.type).toBe('push');
    expect(result.recipient).toBe('carol@test.com');
  });

  it('throws on invalid recipient', () => {
    expect(() => sendEmail('', 'Hi', 'there')).toThrow('Invalid recipient');
    expect(() => sendSms(null, 'Hi', 'there')).toThrow('Invalid recipient');
  });

  it('throws on invalid subject', () => {
    expect(() => sendEmail('a@b.com', '', 'body')).toThrow('Invalid subject');
  });
});
